import { useEffect, useRef, useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import {
  CartView,
  AddressForm,
  AddressList,
  PaymentForm,
  PaymentList,
  SummarySection,
} from "../components/organisms";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import { getPaymentMethods } from "../services/paymentMethodService.js";
import { getShippingAddresses } from "../services/shippingAddressService.js";
import { createOrder } from "../services/orderService.js";
import { Button, ErrorMessage, Loading } from "../components/atoms";
import { normalizeAddress, normalizePayment } from "../utils/storageHelpers.js";
import "./Checkout.css";

export default function Checkout() {
  const navigate = useNavigate();
  const location = useLocation();
  const { user } = useAuth();
  const selectedClient = location.state?.selectedClient || null;
  const {
    cartItems,
    subtotal: cartSubtotal,
    tax: cartTax,
    total: cartTotal,
    clearCart,
  } = useCart();

  // Cálculos financieros simples basados en el carrito
  const subtotal = typeof cartSubtotal === "number" ? cartSubtotal : 0;
  const TAX_RATE = Number(process.env.REACT_APP_TAX_RATE);
  const SHIPPING_RATE = Number(process.env.REACT_APP_SHIPPING_RATE);
  const FREE_SHIPPING_THRESHOLD = Number(
    process.env.REACT_APP_FREE_SHIPPING_THRESHOLD,
  );
  const resolvedTaxRate = Number.isFinite(TAX_RATE) ? TAX_RATE : 0.16;
  const resolvedShippingRate = Number.isFinite(SHIPPING_RATE)
    ? SHIPPING_RATE
    : 350;
  const resolvedFreeShippingThreshold = Number.isFinite(FREE_SHIPPING_THRESHOLD)
    ? FREE_SHIPPING_THRESHOLD
    : 1000;

  const taxAmount = typeof cartTax === "number" ? cartTax : parseFloat((subtotal * resolvedTaxRate).toFixed(2));
  const isEmployee = user?.role === "Cajero" || user?.role === "Administrador";
  const shippingCost = isEmployee
    ? 0
    : (subtotal >= resolvedFreeShippingThreshold ? 0 : resolvedShippingRate);
  const grandTotal = parseFloat(
    (subtotal + taxAmount + shippingCost).toFixed(2),
  );
  const formatMoney = (v) =>
    new Intl.NumberFormat("es-MX", {
      style: "currency",
      currency: "MXN",
    }).format(v);

  // Efecto para redirigir si no hay productos
  useEffect(() => {
    // Si estamos suprimiendo la redirección (p.ej. porque estamos confirmando)
    // no navegamos al carrito aunque esté vacío.
    if (!cartItems || cartItems.length === 0) {
      if (!suppressRedirect.current) {
        navigate("/cart");
      }
    }
  }, [cartItems, navigate]);

  // Flag para evitar redirecciones automáticas cuando estamos confirmando la compra
  const suppressRedirect = useRef(false);

  // Estados para direcciones y métodos de pago (se cargarán desde servicios)
  const [addresses, setAddresses] = useState([]);
  const [payments, setPayments] = useState([]);
  const [loadingLocal, setLoadingLocal] = useState(true);
  const [localError, setLocalError] = useState(null);

  // Estado para controlar la visualización de formularios
  const [showAddressForm, setShowAddressForm] = useState(false);
  const [showPaymentForm, setShowPaymentForm] = useState(false);
  const [editingAddress, setEditingAddress] = useState(null);
  const [editingPayment, setEditingPayment] = useState(null);
  const [addressSectionOpen, setAddressSectionOpen] = useState(true);
  const [paymentSectionOpen, setPaymentSectionOpen] = useState(true);

  // Estado para la selección actual
  const [selectedAddress, setSelectedAddress] = useState(null);
  const [selectedPayment, setSelectedPayment] = useState(null);

  useEffect(() => {
    if (!selectedAddress) {
      setAddressSectionOpen(true);
    }
  }, [selectedAddress]);

  useEffect(() => {
    if (!selectedPayment) {
      setPaymentSectionOpen(true);
    }
  }, [selectedPayment]);

  // Cargar direcciones y métodos desde servicios al montar el componente
  useEffect(() => {
    let isMounted = true;

    async function loadData() {
      if (isEmployee) {
        if (isMounted) setLoadingLocal(false);
        return;
      }

      setLoadingLocal(true);
      setLocalError(null);
      try {
        const [addrList, payList] = await Promise.all([
          getShippingAddresses(),
          getPaymentMethods(),
        ]);

        let addressesWithIds = (addrList || [])
          .map((addr, idx) => normalizeAddress(addr, idx))
          .filter(Boolean);

        let normalizedPayments = (payList || [])
          .map((pay, idx) => normalizePayment(pay, idx))
          .filter(Boolean);

        if (!isMounted) return;

        setAddresses(addressesWithIds);
        setPayments(normalizedPayments);

        const defaultAddr =
          addressesWithIds.find((a) => a.default || a.isDefault) ||
          addressesWithIds[0] ||
          null;
        const defaultPay =
          normalizedPayments.find((p) => p.isDefault || p.default) ||
          normalizedPayments[0] ||
          null;

        setSelectedAddress(defaultAddr);
        setSelectedPayment(defaultPay);
        setAddressSectionOpen(!defaultAddr);
        setPaymentSectionOpen(!defaultPay);
      } catch (err) {
        if (isMounted) {
          console.warn("No se pudieron cargar datos desde el servidor. Usando listas vacías.");
          setAddresses([]);
          setPayments([]);
          // En lugar de bloquear toda la pantalla con localError, lo manejamos suavemente
        }
      } finally {
        if (isMounted) {
          setLoadingLocal(false);
        }
      }
    }

    loadData();
    return () => {
      isMounted = false;
    };
  }, [isEmployee]);

  const handleRetry = () => {
    window.location.reload();
  };

  const persistAddresses = (next) => {
    setAddresses(next);
  };

  const persistPayments = (next) => {
    setPayments(next);
  };

  const handleAddressToggle = () => {
    setShowAddressForm(false);
    setEditingAddress(null);
    setAddressSectionOpen((prev) => !prev);
  };

  const handlePaymentToggle = () => {
    setShowPaymentForm(false);
    setEditingPayment(null);
    setPaymentSectionOpen((prev) => !prev);
  };

  // Manejadores para direcciones
  const handleAddressSubmit = (formData) => {
    let normalizedRecord = normalizeAddress(
      { ...formData, id: editingAddress?.id },
      addresses.length,
    );

    let updatedAddresses = editingAddress
      ? addresses.map((addr) =>
          addr.id === editingAddress.id ? normalizedRecord : addr,
        )
      : [...addresses, normalizedRecord];

    if (normalizedRecord?.default) {
      updatedAddresses = updatedAddresses.map((addr) =>
        addr.id === normalizedRecord.id
          ? { ...addr, default: true, isDefault: true }
          : { ...addr, default: false, isDefault: false },
      );
      normalizedRecord =
        updatedAddresses.find((addr) => addr.id === normalizedRecord.id) ||
        normalizedRecord;
    }

    persistAddresses(updatedAddresses);

    const nextSelection =
      normalizedRecord &&
      (normalizedRecord.default ||
        !selectedAddress ||
        selectedAddress.id === normalizedRecord.id)
        ? normalizedRecord
        : selectedAddress;

    setSelectedAddress(nextSelection);
    setShowAddressForm(false);
    setEditingAddress(null);
    setAddressSectionOpen(false);
  };

  const handleAddressEdit = (address) => {
    setEditingAddress(address);
    setShowAddressForm(true);
    setAddressSectionOpen(true);
  };

  const handleAddressDelete = (addressId) => {
    let updatedAddresses = addresses.filter((addr) => addr.id !== addressId);
    let nextSelection = selectedAddress;

    if (selectedAddress?.id === addressId) {
      nextSelection = null;
    }

    if (updatedAddresses.length > 0) {
      if (!nextSelection) {
        nextSelection =
          updatedAddresses.find((addr) => addr.default || addr.isDefault) ||
          updatedAddresses[0];
      }

      if (nextSelection) {
        updatedAddresses = updatedAddresses.map((addr) =>
          addr.id === nextSelection.id
            ? { ...addr, default: true, isDefault: true }
            : { ...addr, default: false, isDefault: false },
        );
        nextSelection =
          updatedAddresses.find((addr) => addr.id === nextSelection.id) ||
          nextSelection;
      }
    } else {
      nextSelection = null;
    }

    persistAddresses(updatedAddresses);
    setSelectedAddress(nextSelection);
  };

  // Manejadores para métodos de pago
  const handlePaymentSubmit = (formData) => {
    let normalizedRecord = normalizePayment(
      { ...formData, id: editingPayment?.id },
      payments.length,
    );

    let updatedPayments = editingPayment
      ? payments.map((pay) =>
          pay.id === editingPayment.id ? normalizedRecord : pay,
        )
      : [...payments, normalizedRecord];

    if (normalizedRecord?.isDefault || normalizedRecord?.default) {
      updatedPayments = updatedPayments.map((pay) =>
        pay.id === normalizedRecord.id
          ? { ...pay, default: true, isDefault: true }
          : { ...pay, default: false, isDefault: false },
      );
      normalizedRecord =
        updatedPayments.find((pay) => pay.id === normalizedRecord.id) ||
        normalizedRecord;
    }

    persistPayments(updatedPayments);

    const nextSelection =
      normalizedRecord &&
      (normalizedRecord.isDefault ||
        normalizedRecord.default ||
        !selectedPayment ||
        selectedPayment.id === normalizedRecord.id)
        ? normalizedRecord
        : selectedPayment;

    setSelectedPayment(nextSelection);
    setShowPaymentForm(false);
    setEditingPayment(null);
    setPaymentSectionOpen(false);
  };

  const handlePaymentEdit = (payment) => {
    setEditingPayment(payment);
    setShowPaymentForm(true);
    setPaymentSectionOpen(true);
  };

  const handlePaymentDelete = (paymentId) => {
    let updatedPayments = payments.filter((pay) => pay.id !== paymentId);
    let nextSelection = selectedPayment;

    if (selectedPayment?.id === paymentId) {
      nextSelection = null;
    }

    if (updatedPayments.length > 0) {
      if (!nextSelection) {
        nextSelection =
          updatedPayments.find((pay) => pay.isDefault || pay.default) ||
          updatedPayments[0];
      }

      if (nextSelection) {
        updatedPayments = updatedPayments.map((pay) =>
          pay.id === nextSelection.id
            ? { ...pay, default: true, isDefault: true }
            : { ...pay, default: false, isDefault: false },
        );
        nextSelection =
          updatedPayments.find((pay) => pay.id === nextSelection.id) ||
          nextSelection;
      }
    } else {
      nextSelection = null;
    }

    persistPayments(updatedPayments);
    setSelectedPayment(nextSelection);
  };

  return (
    // Mostrar loading o error antes del contenido principal
    loadingLocal ? (
      <div className="checkout-loading">
        <Loading message="Cargando direcciones y métodos de pago..." />
      </div>
    ) : localError ? (
      <div className="checkout-error">
        <ErrorMessage message={localError}>
          <div style={{ textAlign: "center", marginTop: 12 }}>
            <Button onClick={handleRetry} variant="primary">
              Reintentar
            </Button>
          </div>
        </ErrorMessage>
      </div>
    ) : (
      <div className="checkout-container">
        <div className="checkout-left">
          <SummarySection
            title="1. Dirección de envío"
            selected={isEmployee ? true : selectedAddress}
            summaryContent={
              isEmployee ? (
                <div className="selected-address">
                  <p>Venta física en Tienda</p>
                </div>
              ) : (
                <div className="selected-address">
                  <p>{selectedAddress?.name}</p>
                  <p>{selectedAddress?.address1}</p>
                  <p>
                    {selectedAddress?.city}, {selectedAddress?.postalCode}
                  </p>
                </div>
              )
            }
            isExpanded={
              !isEmployee && (showAddressForm || addressSectionOpen || !selectedAddress)
            }
            onToggle={isEmployee ? undefined : handleAddressToggle}
          >
            {!isEmployee && (
              !showAddressForm && !editingAddress ? (
                <AddressList
                  addresses={addresses}
                  selectedAddress={selectedAddress}
                  onSelect={(address) => {
                    setSelectedAddress(address);
                    setShowAddressForm(false);
                    setEditingAddress(null);
                    setAddressSectionOpen(false);
                  }}
                  onEdit={handleAddressEdit}
                  onDelete={handleAddressDelete}
                  onAdd={() => {
                    setEditingAddress(null);
                    setShowAddressForm(true);
                    setAddressSectionOpen(true);
                  }}
                />
              ) : (
                <AddressForm
                  key={editingAddress?.id || "new"}
                  onSubmit={handleAddressSubmit}
                  onCancel={() => {
                    setShowAddressForm(false);
                    setEditingAddress(null);
                    setAddressSectionOpen(true);
                  }}
                  initialValues={editingAddress || {}}
                  isEdit={!!editingAddress}
                />
              )
            )}
          </SummarySection>

          <SummarySection
            title="2. Método de pago"
            selected={isEmployee ? true : selectedPayment}
            summaryContent={
              isEmployee ? (
                <div className="selected-payment">
                  <p>Cobro en Caja</p>
                  <p>Efectivo / Tarjeta física</p>
                </div>
              ) : (
                <div className="selected-payment">
                  <p>{selectedPayment?.alias}</p>
                  <p>**** {selectedPayment?.cardNumber?.slice(-4) || "----"}</p>
                </div>
              )
            }
            isExpanded={
              !isEmployee && (showPaymentForm || paymentSectionOpen || !selectedPayment)
            }
            onToggle={isEmployee ? undefined : handlePaymentToggle}
          >
            {!isEmployee && (
              !showPaymentForm && !editingPayment ? (
                <PaymentList
                  payments={payments}
                  selectedPayment={selectedPayment}
                  onSelect={(payment) => {
                    setSelectedPayment(payment);
                    setShowPaymentForm(false);
                    setEditingPayment(null);
                    setPaymentSectionOpen(false);
                  }}
                  onEdit={handlePaymentEdit}
                  onDelete={handlePaymentDelete}
                  onAdd={() => {
                    setEditingPayment(null);
                    setShowPaymentForm(true);
                    setPaymentSectionOpen(true);
                  }}
                />
              ) : (
                <PaymentForm
                  key={editingPayment?.id || "new"}
                  onSubmit={handlePaymentSubmit}
                  onCancel={() => {
                    setShowPaymentForm(false);
                    setEditingPayment(null);
                    setPaymentSectionOpen(true);
                  }}
                  initialValues={editingPayment || {}}
                  isEdit={!!editingPayment}
                />
              )
            )}
          </SummarySection>

          <SummarySection
            title="3. Revisa tu pedido"
            selected={true}
            isExpanded={true}
          >
            <CartView />
          </SummarySection>
        </div>

        <div className="checkout-right">
          <div className="checkout-summary">
            <h3>Resumen de la Orden</h3>

            <div className="summary-items">
              {cartItems.map((item) => (
                <div key={item._id} className="summary-item">
                  <div className="summary-item-info">
                    <span className="summary-item-qty">{item.quantity}x</span>
                    <span className="summary-item-name">{item.name}</span>
                  </div>
                  <span className="summary-item-price">{formatMoney(item.price * item.quantity)}</span>
                </div>
              ))}
            </div>

            <div className="summary-details">
              <p>
                <strong>Dirección de envío:</strong> {isEmployee ? "Venta en Tienda" : (selectedAddress?.name || "No seleccionada")}
              </p>
              <p>
                <strong>Método de pago:</strong> {isEmployee ? "Efectivo / Caja" : (selectedPayment?.alias || "No seleccionado")}
              </p>
              <div className="order-costs">
                <p>
                  <strong>Subtotal:</strong> {formatMoney(subtotal)}
                </p>
                <p>
                  <strong>IVA (16%):</strong> {formatMoney(taxAmount)}
                </p>
                {!isEmployee && (
                  <p>
                    <strong>Envío:</strong>{" "}
                    {shippingCost === 0 ? "Gratis" : formatMoney(shippingCost)}
                  </p>
                )}
                <hr />
                <p>
                  <strong>Total:</strong> {formatMoney(grandTotal)}
                </p>
              </div>
              {!isEmployee && (
                <p>
                  <strong>Fecha estimada de entrega:</strong>{" "}
                  {new Date(
                    Date.now() + 7 * 24 * 60 * 60 * 1000,
                  ).toLocaleDateString()}
                </p>
              )}
            </div>
            <Button
              className="pay-button"
              disabled={
                (!isEmployee && (!selectedAddress || !selectedPayment)) ||
                !cartItems ||
                cartItems.length === 0
              }
              title={
                !cartItems || cartItems.length === 0
                  ? "No hay productos en el carrito"
                  : !isEmployee && !selectedAddress
                    ? "Selecciona una dirección de envío"
                    : !isEmployee && !selectedPayment
                      ? "Selecciona un método de pago"
                      : "Confirmar y realizar el pago"
              }
              onClick={async () => {
                setLoadingLocal(true);
                try {
                  const payload = {
                    usuario: selectedClient?._id || selectedClient?.id || user?._id || user?.id,
                    items: cartItems.map((item) => ({
                      _id: item._id,
                      name: item.name,
                      price: item.price,
                      quantity: item.quantity,
                    })),
                    total: grandTotal,
                    paymentMethod: selectedPayment || { alias: "Efectivo" },
                    shippingAddress: selectedAddress || {
                      name: "En Tienda",
                      address1: "Venta física",
                      city: "Cafetería",
                      postalCode: "00000",
                    },
                    shippingCost: shippingCost,
                  };

                  const newOrder = await createOrder(payload);

                  suppressRedirect.current = true;
                  clearCart();

                  navigate("/order-confirmation", {
                    state: { order: newOrder },
                  });
                } catch (error) {
                  setLocalError(
                    error.response?.data?.message ||
                      "Hubo un problema procesando tu orden. Verifica tu stock.",
                  );
                } finally {
                  setLoadingLocal(false);
                }
              }}
              data-testid="confirm-order-btn"
            >
              Confirmar y Pagar
            </Button>
          </div>
        </div>
      </div>
    )
  );
}
